import{_ as l,o as e,c as i,ag as d}from"./chunks/framework.CKZNj4UW.js";const g=JSON.parse('{"title":"支持的文件类型","description":"","frontmatter":{},"headers":[],"relativePath":"guide/supported-types.md","filePath":"guide/supported-types.md"}'),t={name:"guide/supported-types.md"};function a(r,o,c,n,s,h){return e(),i("div",null,[...o[0]||(o[0]=[d('<h1 id="支持的文件类型" tabindex="-1">支持的文件类型 <a class="header-anchor" href="#支持的文件类型" aria-label="Permalink to &quot;支持的文件类型&quot;">​</a></h1><p>File Preview 支持多种常见的文件格式预览（React 与 Vue 两个版本能力完全对齐）。</p><h2 id="图片格式" tabindex="-1">图片格式 <a class="header-anchor" href="#图片格式" aria-label="Permalink to &quot;图片格式&quot;">​</a></h2><p>支持所有浏览器原生支持的图片格式：</p><ul><li><strong>JPEG/JPG</strong> - <code>.jpg</code>, <code>.jpeg</code></li><li><strong>PNG</strong> - <code>.png</code></li><li><strong>GIF</strong> - <code>.gif</code> (支持动画)</li><li><strong>WebP</strong> - <code>.webp</code></li><li><strong>SVG</strong> - <code>.svg</code></li><li><strong>BMP</strong> - <code>.bmp</code></li><li><strong>ICO</strong> - <code>.ico</code></li></ul><h3 id="特性" tabindex="-1">特性 <a class="header-anchor" href="#特性" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>缩放和平移（范围 0.01x - 10x）</li><li>旋转（顺时针/逆时针 90°）</li><li>鼠标滚轮缩放</li><li>拖拽移动</li></ul><h3 id="高级图片格式" tabindex="-1">高级图片格式 <a class="header-anchor" href="#高级图片格式" aria-label="Permalink to &quot;高级图片格式&quot;">​</a></h3><p>针对浏览器不原生支持的格式，库会自动按需动态加载内置的解码引擎，主 bundle 体积零增量；运行时仅在用户实际预览对应格式时才下载解码 chunk。</p><ul><li><strong>HEIC/HEIF</strong> - <code>.heic</code>, <code>.heif</code><ul><li>Apple 设备（iPhone/iPad）从 iOS 11 起的默认照片格式</li><li>解码引擎：<code>heic2any</code>（解码时间 0.5-2s，取决于分辨率）</li><li>在 Web Worker 中解码，不阻塞 UI</li></ul></li><li><strong>AVIF</strong> - <code>.avif</code><ul><li>现代高压缩比格式（比 JPEG 节省 ~50% 体积）</li><li>Chrome 85+、Firefox 93+、Safari 16+ 已原生支持，自动检测</li><li>不支持时降级到 WASM 解码（<code>@jsquash/avif</code>）</li></ul></li><li><strong>TIFF</strong> - <code>.tif</code>, <code>.tiff</code><ul><li>常见于扫描文档、印刷预检</li><li>解码引擎：<code>utif</code></li><li>支持多页 TIFF：底部出现「上一页 / 下一页」按钮</li><li>内置 LRU 缓存（最多 10 页），翻页流畅</li></ul></li><li><strong>RAW 相机原始格式</strong> - <code>.cr2</code>, <code>.nef</code>, <code>.arw</code>, <code>.dng</code>, <code>.raf</code>, <code>.orf</code><ul><li>支持 Canon (CR2)、Nikon (NEF)、Sony (ARW)、Adobe (DNG)、Fujifilm (RAF)、Olympus (ORF)</li><li>通过解析容器结构提取嵌入的 JPEG 预览图（零额外依赖，&lt; 500ms）</li><li>当前版本不进行完整像素级解码（受浏览器端 RAW 引擎成熟度限制）</li></ul></li><li><strong>PSD（Adobe Photoshop）</strong> - <code>.psd</code><ul><li>解码引擎：<code>ag-psd</code></li><li>仅展示合并图层后的最终效果，不解析图层结构</li><li>带蒙版 / 调整图层的 PSD 显示可能与 Photoshop 略有差异</li></ul></li><li><strong>JPEG 2000</strong> - <code>.jp2</code>, <code>.jpx</code>, <code>.j2k</code><ul><li>Safari 原生支持，其他浏览器通过 WASM 解码（<code>@jsquash/jpeg2000</code>）</li><li>常见于医学影像、地图瓦片</li></ul></li></ul><h4 id="浏览器兼容性" tabindex="-1">浏览器兼容性 <a class="header-anchor" href="#浏览器兼容性" aria-label="Permalink to &quot;浏览器兼容性&quot;">​</a></h4><table tabindex="0"><thead><tr><th>格式</th><th>Chrome</th><th>Firefox</th><th>Safari</th><th>Edge</th></tr></thead><tbody><tr><td>HEIC/HEIF</td><td>WASM</td><td>WASM</td><td>WASM</td><td>WASM</td></tr><tr><td>AVIF</td><td>原生 (85+)</td><td>原生 (93+)</td><td>原生 (16+)</td><td>原生 (90+)</td></tr><tr><td>TIFF</td><td>WASM</td><td>WASM</td><td>部分原生</td><td>WASM</td></tr><tr><td>RAW</td><td>嵌入预览</td><td>嵌入预览</td><td>嵌入预览</td><td>嵌入预览</td></tr><tr><td>PSD</td><td>WASM</td><td>WASM</td><td>WASM</td><td>WASM</td></tr><tr><td>JPEG 2000</td><td>WASM</td><td>WASM</td><td>原生</td><td>WASM</td></tr></tbody></table><h4 id="性能特征" tabindex="-1">性能特征 <a class="header-anchor" href="#性能特征" aria-label="Permalink to &quot;性能特征&quot;">​</a></h4><ul><li>HEIC/RAW/PSD 等耗时解码（&gt; 500ms）在 Web Worker 中执行，不阻塞主线程</li><li>TIFF/AVIF 在主线程解码（&lt; 100ms）</li><li>所有解码引擎通过动态 <code>import()</code> 按需加载，未使用的格式不会进入首屏 chunk</li><li>解码失败时显示友好提示</li></ul><h2 id="视频格式" tabindex="-1">视频格式 <a class="header-anchor" href="#视频格式" aria-label="Permalink to &quot;视频格式&quot;">​</a></h2><p>支持 HTML5 视频格式：</p><ul><li><strong>MP4</strong> - <code>.mp4</code></li><li><strong>WebM</strong> - <code>.webm</code></li><li><strong>OGG</strong> - <code>.ogg</code>, <code>.ogv</code></li><li><strong>MOV</strong> - <code>.mov</code></li><li><strong>AVI</strong> - <code>.avi</code></li><li><strong>MKV</strong> - <code>.mkv</code></li><li><strong>M4V</strong> - <code>.m4v</code></li><li><strong>3GP</strong> - <code>.3gp</code></li><li><strong>FLV</strong> - <code>.flv</code></li></ul><h3 id="特性-1" tabindex="-1">特性 <a class="header-anchor" href="#特性-1" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>基于 Video.js 播放器</li><li>播放/暂停控制</li><li>音量调节</li><li>进度条</li><li>全屏播放</li></ul><h2 id="音频格式" tabindex="-1">音频格式 <a class="header-anchor" href="#音频格式" aria-label="Permalink to &quot;音频格式&quot;">​</a></h2><p>支持 HTML5 音频格式：</p><ul><li><strong>MP3</strong> - <code>.mp3</code></li><li><strong>WAV</strong> - <code>.wav</code></li><li><strong>OGG</strong> - <code>.ogg</code></li><li><strong>M4A</strong> - <code>.m4a</code></li><li><strong>AAC</strong> - <code>.aac</code></li><li><strong>FLAC</strong> - <code>.flac</code></li></ul><h3 id="特性-2" tabindex="-1">特性 <a class="header-anchor" href="#特性-2" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>播放/暂停控制</li><li>音量调节</li><li>进度条</li><li>快进/快退（±10 秒）</li></ul><h2 id="pdf-文档" tabindex="-1">PDF 文档 <a class="header-anchor" href="#pdf-文档" aria-label="Permalink to &quot;PDF 文档&quot;">​</a></h2><ul><li><strong>PDF</strong> - <code>.pdf</code></li></ul><h3 id="特性-3" tabindex="-1">特性 <a class="header-anchor" href="#特性-3" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>页面导航（上一页/下一页）</li><li>缩放控制（0.01x - 10x）</li><li>连续滚动浏览</li><li>页码显示</li></ul><h2 id="office-文档" tabindex="-1">Office 文档 <a class="header-anchor" href="#office-文档" aria-label="Permalink to &quot;Office 文档&quot;">​</a></h2><h3 id="word-文档" tabindex="-1">Word 文档 <a class="header-anchor" href="#word-文档" aria-label="Permalink to &quot;Word 文档&quot;">​</a></h3><ul><li><strong>DOCX</strong> - <code>.docx</code></li></ul><h3 id="excel-表格" tabindex="-1">Excel 表格 <a class="header-anchor" href="#excel-表格" aria-label="Permalink to &quot;Excel 表格&quot;">​</a></h3><ul><li><strong>XLSX</strong> - <code>.xlsx</code></li></ul><h3 id="powerpoint-演示文稿" tabindex="-1">PowerPoint 演示文稿 <a class="header-anchor" href="#powerpoint-演示文稿" aria-label="Permalink to &quot;PowerPoint 演示文稿&quot;">​</a></h3><ul><li><strong>PPTX</strong> - <code>.pptx</code></li><li><strong>PPT</strong> - <code>.ppt</code></li></ul><h3 id="特性-4" tabindex="-1">特性 <a class="header-anchor" href="#特性-4" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>保留原始格式</li><li>支持图片和表格</li><li>响应式布局</li><li>显示所有工作表（Excel）</li><li>平铺/幻灯片两种显示模式（PowerPoint，16:9 宽高比）</li></ul><h2 id="outlook-邮件" tabindex="-1">Outlook 邮件 <a class="header-anchor" href="#outlook-邮件" aria-label="Permalink to &quot;Outlook 邮件&quot;">​</a></h2><ul><li><strong>MSG</strong> - <code>.msg</code></li></ul><h3 id="特性-5" tabindex="-1">特性 <a class="header-anchor" href="#特性-5" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>解析邮件头信息（发件人、收件人、主题、日期）</li><li>邮件正文渲染</li><li>附件列表展示</li></ul><h2 id="电子书" tabindex="-1">电子书 <a class="header-anchor" href="#电子书" aria-label="Permalink to &quot;电子书&quot;">​</a></h2><h3 id="epub" tabindex="-1">EPUB <a class="header-anchor" href="#epub" aria-label="Permalink to &quot;EPUB&quot;">​</a></h3><ul><li><strong>EPUB</strong> - <code>.epub</code></li></ul><h4 id="特性-6" tabindex="-1">特性 <a class="header-anchor" href="#特性-6" aria-label="Permalink to &quot;特性&quot;">​</a></h4><ul><li>基于 foliate-js 渲染，零外部 CDN 依赖</li><li>章节导航（目录侧栏）</li><li>左右翻页（按钮 / 键盘方向键）</li><li>章节自动分页与页码显示</li><li>全屏宽度 / 阅读宽度切换</li><li>自适应屏幕宽度</li></ul><h3 id="mobi-azw-kf8" tabindex="-1">MOBI / AZW / KF8 <a class="header-anchor" href="#mobi-azw-kf8" aria-label="Permalink to &quot;MOBI / AZW / KF8&quot;">​</a></h3><ul><li><strong>MOBI</strong> - <code>.mobi</code></li><li><strong>AZW / AZW3</strong> - <code>.azw</code>, <code>.azw3</code></li><li><strong>KF8</strong> - <code>.kf8</code></li></ul><h4 id="特性-7" tabindex="-1">特性 <a class="header-anchor" href="#特性-7" aria-label="Permalink to &quot;特性&quot;">​</a></h4><ul><li>基于 foliate-js 解析与渲染（与 EPUB 共用底层）</li><li>与 EPUB 一致的翻页 / 目录 / 全屏宽度交互</li><li>不支持 DRM 保护文件，遇到 DRM 会给出明确提示</li></ul><h2 id="字体文件" tabindex="-1">字体文件 <a class="header-anchor" href="#字体文件" aria-label="Permalink to &quot;字体文件&quot;">​</a></h2><ul><li><strong>TrueType</strong> - <code>.ttf</code></li><li><strong>OpenType</strong> - <code>.otf</code></li><li><strong>WOFF</strong> - <code>.woff</code></li><li><strong>WOFF2</strong> - <code>.woff2</code></li></ul><h3 id="特性-8" tabindex="-1">特性 <a class="header-anchor" href="#特性-8" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>基于 opentype.js 解析字体内部结构</li><li>展示完整元数据：字体家族、子系列、版本、设计师、字形数量、格式</li><li>多字号梯度展示（72 / 48 / 36 / 24 / 18 px）</li><li>自定义文本输入框，实时预览效果</li><li>内置拉丁字母与中文常用字字符集样例</li><li>双渲染策略 <ul><li>优先使用浏览器原生 FontFace API（性能最佳）</li><li>浏览器 OTS（OpenType Sanitizer）拒绝时自动降级到 Canvas 软渲染（opentype.js 容忍度更高，可显示部分浏览器原生不接受的字体）</li></ul></li><li>容器宽度固定，长文本自动按容器宽度断行</li></ul><h2 id="markdown-文档" tabindex="-1">Markdown 文档 <a class="header-anchor" href="#markdown-文档" aria-label="Permalink to &quot;Markdown 文档&quot;">​</a></h2><ul><li><strong>Markdown</strong> - <code>.md</code>, <code>.markdown</code></li></ul><h3 id="特性-9" tabindex="-1">特性 <a class="header-anchor" href="#特性-9" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>GitHub Flavored Markdown (GFM) 支持</li><li>代码语法高亮</li><li>表格支持</li><li>任务列表</li><li>自动链接</li></ul><h2 id="代码文件" tabindex="-1">代码文件 <a class="header-anchor" href="#代码文件" aria-label="Permalink to &quot;代码文件&quot;">​</a></h2><p>支持 40+ 种编程语言的语法高亮：</p><ul><li><strong>JavaScript/TypeScript</strong> - <code>.js</code>, <code>.jsx</code>, <code>.ts</code>, <code>.tsx</code></li><li><strong>Python</strong> - <code>.py</code></li><li><strong>Java</strong> - <code>.java</code></li><li><strong>C/C++</strong> - <code>.c</code>, <code>.cpp</code>, <code>.h</code></li><li><strong>C#</strong> - <code>.cs</code></li><li><strong>Go</strong> - <code>.go</code>, <code>.mod</code></li><li><strong>Rust</strong> - <code>.rs</code></li><li><strong>Lua</strong> - <code>.lua</code></li><li><strong>Vim Script</strong> - <code>.vim</code></li><li><strong>PHP</strong> - <code>.php</code></li><li><strong>Ruby</strong> - <code>.rb</code></li><li><strong>Swift</strong> - <code>.swift</code></li><li><strong>Kotlin</strong> - <code>.kt</code></li><li><strong>HTML</strong> - <code>.html</code></li><li><strong>CSS/SCSS/Sass/Less</strong> - <code>.css</code>, <code>.scss</code>, <code>.sass</code>, <code>.less</code></li><li><strong>YAML</strong> - <code>.yaml</code>, <code>.yml</code></li><li><strong>TOML</strong> - <code>.toml</code></li><li><strong>INI</strong> - <code>.ini</code>, <code>.conf</code>, <code>.env</code></li><li><strong>Lock 文件</strong> - <code>.lock</code></li><li><strong>Diff/Patch</strong> - <code>.diff</code>, <code>.patch</code></li><li><strong>Shell</strong> - <code>.sh</code>, <code>.bash</code>, <code>.zsh</code></li><li><strong>SQL</strong> - <code>.sql</code></li><li><strong>Log</strong> - <code>.log</code></li></ul><h3 id="特性-10" tabindex="-1">特性 <a class="header-anchor" href="#特性-10" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>语法高亮（VS Code Dark+ 主题）</li><li>自动语言检测</li><li>行号显示</li></ul><h2 id="csv-tsv-表格" tabindex="-1">CSV / TSV 表格 <a class="header-anchor" href="#csv-tsv-表格" aria-label="Permalink to &quot;CSV / TSV 表格&quot;">​</a></h2><ul><li><strong>CSV</strong> - <code>.csv</code></li><li><strong>TSV</strong> - <code>.tsv</code></li></ul><h3 id="特性-11" tabindex="-1">特性 <a class="header-anchor" href="#特性-11" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>纯前端解析，无第三方依赖</li><li>支持 RFC 4180 双引号转义与字段内换行</li><li>表格式渲染，首行自动识别为表头</li><li>显示行数/列数统计</li></ul><h2 id="xml" tabindex="-1">XML <a class="header-anchor" href="#xml" aria-label="Permalink to &quot;XML&quot;">​</a></h2><ul><li><strong>XML</strong> - <code>.xml</code></li></ul><h3 id="特性-12" tabindex="-1">特性 <a class="header-anchor" href="#特性-12" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>使用浏览器原生 <code>DOMParser</code> 做格式校验</li><li>自动缩进美化</li><li>语法高亮</li></ul><h2 id="字幕-歌词文件" tabindex="-1">字幕 / 歌词文件 <a class="header-anchor" href="#字幕-歌词文件" aria-label="Permalink to &quot;字幕 / 歌词文件&quot;">​</a></h2><ul><li><strong>SRT</strong> - <code>.srt</code></li><li><strong>WebVTT</strong> - <code>.vtt</code></li><li><strong>LRC</strong> - <code>.lrc</code>（基础歌词，<code>[mm:ss.xx]</code> 行时间戳，支持 <code>[ti:][ar:][al:]</code> 等元数据）</li><li><strong>Enhanced LRC</strong> - <code>.elrc</code>（增强歌词，行内 <code>&lt;mm:ss.xx&gt;</code> 逐字时间戳）</li><li><strong>ASS / SSA</strong> - <code>.ass</code> / <code>.ssa</code>（Advanced SubStation Alpha，自动剥离 <code>\\N</code> <code>\\h</code> 与 <code>{...}</code> 样式覆盖码）</li><li><strong>TTML / DFXP</strong> - <code>.ttml</code> / <code>.dfxp</code>（W3C / Apple Music 使用的 XML 字幕，支持 <code>begin</code> / <code>end</code> / <code>dur</code> 与 <code>&lt;br/&gt;</code>）</li></ul><h3 id="特性-13" tabindex="-1">特性 <a class="header-anchor" href="#特性-13" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>纯前端解析，零第三方依赖</li><li>自动按内容/扩展名识别格式</li><li>结构化 cue 列表展示（索引、时间区间、文本）</li><li>LRC / ELRC 自动展示元数据（标题 / 艺术家 / 专辑 / 偏移……）</li><li>ELRC 逐字时间戳以词条形式排列展示</li><li>ASS / SSA 同步显示 Style 标签，自动应用 <code>offset</code> 偏移</li></ul><h2 id="json-jsonc" tabindex="-1">JSON / JSONC <a class="header-anchor" href="#json-jsonc" aria-label="Permalink to &quot;JSON / JSONC&quot;">​</a></h2><ul><li><strong>JSON</strong> - <code>.json</code></li><li><strong>JSONC (JSON with Comments)</strong> - <code>.jsonc</code></li></ul><h3 id="特性-14" tabindex="-1">特性 <a class="header-anchor" href="#特性-14" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>自动格式化缩进</li><li>语法高亮</li><li><strong>支持注释</strong>（JSONC） <ul><li>单行注释 <code>//</code></li><li>多行注释 <code>/* */</code></li><li>行尾注释</li><li>基于 <code>jsonc-parser</code>（Microsoft 官方，VSCode 同款）</li></ul></li></ul><h2 id="zip-压缩包" tabindex="-1">ZIP 压缩包 <a class="header-anchor" href="#zip-压缩包" aria-label="Permalink to &quot;ZIP 压缩包&quot;">​</a></h2><ul><li><strong>ZIP</strong> - <code>.zip</code></li></ul><h3 id="特性-15" tabindex="-1">特性 <a class="header-anchor" href="#特性-15" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>基于 JSZip 解析压缩包目录结构</li><li>左侧树形目录 + 右侧内嵌预览</li><li>内嵌预览文本、代码（带高亮）与图片</li><li>其他类型可通过&quot;下载&quot;按钮导出为独立文件</li></ul><h2 id="纯文本" tabindex="-1">纯文本 <a class="header-anchor" href="#纯文本" aria-label="Permalink to &quot;纯文本&quot;">​</a></h2><ul><li><strong>TXT</strong> - <code>.txt</code></li><li>其他未识别的文本文件</li></ul><h2 id="不支持的格式" tabindex="-1">不支持的格式 <a class="header-anchor" href="#不支持的格式" aria-label="Permalink to &quot;不支持的格式&quot;">​</a></h2><p>对于不支持的文件格式，组件会显示一个友好的提示界面，包含：</p><ul><li>文件名和大小</li><li>下载按钮</li><li>文件类型说明</li></ul><h2 id="文件类型检测" tabindex="-1">文件类型检测 <a class="header-anchor" href="#文件类型检测" aria-label="Permalink to &quot;文件类型检测&quot;">​</a></h2><p>组件会按以下优先级检测文件类型：</p><ol><li><strong>MIME 类型</strong>：如果提供了 <code>type</code> 属性，优先使用</li><li><strong>文件扩展名</strong>：从文件名自动推断 MIME 类型</li><li><strong>默认类型</strong>：无法识别时标记为 <code>unsupported</code></li></ol><p>支持的文件类型枚举：</p><ul><li><code>image</code> - 图片文件</li><li><code>pdf</code> - PDF 文档</li><li><code>docx</code> - Word 文档</li><li><code>xlsx</code> - Excel 表格</li><li><code>pptx</code> - PowerPoint 演示文稿</li><li><code>msg</code> - Outlook 邮件</li><li><code>epub</code> - EPUB 电子书</li><li><code>mobi</code> - MOBI / AZW / AZW3 / KF8 电子书</li><li><code>video</code> - 视频文件</li><li><code>audio</code> - 音频文件</li><li><code>markdown</code> - Markdown 文件</li><li><code>json</code> - JSON / JSONC 文件</li><li><code>csv</code> - CSV/TSV 文件</li><li><code>xml</code> - XML 文件</li><li><code>subtitle</code> - SRT / VTT / LRC / ELRC / ASS / SSA / TTML 字幕与歌词文件</li><li><code>zip</code> - ZIP 压缩包</li><li><code>text</code> - 其他文本和代码文件</li><li><code>font</code> - 字体文件（TTF / OTF / WOFF / WOFF2）</li><li><code>unsupported</code> - 不支持的类型</li></ul>',93)])])}const b=l(t,[["render",a]]);export{g as __pageData,b as default};
